const BackgroundWaves = () => {
  const totalLines = 17;

  return (
    <>
      <style>{`
        @keyframes wave-slide {
          0%   { transform: translateX(0px) scaleY(1); }
          25%  { transform: translateX(-30px) scaleY(1.3); }
          50%  { transform: translateX(-60px) scaleY(0.8); }
          75%  { transform: translateX(-20px) scaleY(1.4); }
          100% { transform: translateX(0px) scaleY(1); }
        }
        @keyframes wave-slide-b {
          0%   { transform: translateX(0px) scaleY(0.9); }
          30%  { transform: translateX(40px) scaleY(1.4); }
          60%  { transform: translateX(15px) scaleY(0.7); }
          100% { transform: translateX(0px) scaleY(0.9); }
        }
        @keyframes wave-slide-c {
          0%   { transform: translateX(0px) scaleY(1.1); }
          40%  { transform: translateX(-50px) scaleY(0.75); }
          70%  { transform: translateX(25px) scaleY(1.5); }
          100% { transform: translateX(0px) scaleY(1.1); }
        }
        @keyframes slow-float {
          0%, 100% { transform: translateY(0px); }
          50%       { transform: translateY(-10px); }
        }
      `}</style>

      <svg
        viewBox="0 0 1440 900"
        preserveAspectRatio="none"
        className="absolute inset-0 w-full h-full pointer-events-none z-0"
      >
        {[...Array(totalLines)].map((_, i) => {
          const anims = ["wave-slide", "wave-slide-b", "wave-slide-c"];
          const anim = anims[i % 3];
          const duration = 8 + i * 0.8;
          const y = (900 / (totalLines - 1)) * i;

          return (
            <g
              key={i}
              style={{
                animation: `slow-float ${4 + i * 0.35}s ease-in-out infinite`,
                animationDelay: `${-(i * 0.5)}s`,
                transformOrigin: `720px ${y}px`,
              }}
            >
              <path
                d={`M-200,${y} C-80,${y - 12} 120,${y + 10} 260,${y - 8}
                    C400,${y + 16} 560,${y - 6} 720,${y + 12}
                    C880,${y - 14} 1040,${y + 8} 1200,${y - 4}
                    C1360,${y + 10} 1520,${y - 8} 1640,${y + 6}`}
                fill="none"
                stroke="#F3FEFF"
                strokeWidth={i % 4 === 0 ? "1.6" : "1"}
                opacity={0.45 + (i % 3) * 0.15}
                style={{
                  animation: `${anim} ${duration}s ease-in-out infinite`,
                  animationDelay: `${-(i * 0.65)}s`,
                  transformOrigin: `720px ${y}px`,
                }}
              />
            </g>
          );
        })}
      </svg>
    </>
  );
};

export default BackgroundWaves;
